const PAKISTAN_CITIES = ['pakistan', 'islamabad', 'rawalpindi', 'lahore', 'karachi', 'peshawar', 'multan', 'faisalabad'];

function isInPakistan(job) {
  const location = (job.location || '').toLowerCase();
  return PAKISTAN_CITIES.some(city => location.includes(city));
}

const results = [];
const seen = new Set();

for (const input of $input.all()) {
  const jobs = input.json?.data || [];
  for (const job of jobs) {
    if (!job.job_id || seen.has(job.job_id)) continue;
    if (!isInPakistan(job)) continue;
    seen.add(job.job_id);
    results.push({ json: job });
  }
}

return results;

const AI_KEYWORDS = [
  'ai engineer',
  'junior ai',
  'ai/ml',
  'ai ml',
  'agentic',
  'artificial intelligence',
  'machine learning',
  'ml engineer',
  'automation engineer',
  'ai specialist'
];

const keywords = AI_KEYWORDS.map(k => k.toLowerCase());

return $input.all().filter(item => {
  const title = (item.json.title || '').toLowerCase();
  const tags = (item.json.tags || '').toLowerCase();
  const searchText = title + ' ' + tags;
  return keywords.some(kw => searchText.includes(kw));
});

const EXP_RE = /(\d+)\s*(?:[-\u2013]\s*\d+)?\s*\+?\s*years?(?:\s+of)?(?:\s+experience)?/gi;

function minYearsRequired(text) {
  const matches = [...text.matchAll(EXP_RE)];
  if (matches.length === 0) return null;
  return Math.min(...matches.map(m => parseInt(m[1], 10)));
}

return $input.all().filter(item => {
  const text = [
    (item.json.title       || ''),
    (item.json.description || '')
  ].join(' ');

  const minYears = minYearsRequired(text);
  if (minYears === null) return true;
  return minYears < 2;
});
